                'app/modules/RxnSync/RxnSyncController.php index(): precondiciones CRM ahora leen listasReady y depositoReady de countByType(empresaId, tipo). Agregado flag catalogos_ready = !empty(tango_connect_token). El syncCircuit array expone area + catalogos_ready + sync_catalogos_path.',
                'app/config/routes.php: nueva ruta POST /mi-empresa/crm/rxn-sync/sync-catalogos con guard requireCrm. Ruta vieja POST /mi-empresa/crm/presupuestos/catalogos/sincronizar ELIMINADA.',
